cadishfile:
example.com {
    @lang_es header_regex Accept-Language (?i)^es
    @lang_en header_regex Accept-Language (?i)^en
    classify {langredir} { when @lang_es -> es ; when @lang_en -> en ; default -> none }
    @es_target classify {langredir}==es
    @en_target classify {langredir}==en
    redirect @es_target (?i)^(.*)/(couples|parejas)/?$ 301 https://{host}$1/parejas
    redirect @en_target (?i)^(.*)/(couples|parejas)/?$ 301 https://{host}$1/couples

    cache_key host path
    cache_ttl default ttl 1m grace 5m
}
